SELECT 
    (SELECT year FROM economic_data ORDER BY unemp DESC LIMIT 1) AS year_with_highest_unemployment,
    (SELECT AVG(pop) FROM economic_data) AS average_population;

SELECT totemp
FROM economic_data
WHERE pop = (SELECT MAX(pop) FROM economic_data);

SELECT query_type, query_result
FROM data_queries
WHERE query_status = 'completed';

SELECT DISTINCT year
FROM economic_data
ORDER BY year;

SELECT totemp
FROM economic_data
WHERE entry_date LIKE '2023-%' AND data_quality = 'high';

SELECT DISTINCT year
FROM economic_data
WHERE data_quality = 'high';
